import * as React from 'react';
import { handleError } from '@/shared/lib/errorHandling/handleError';

const MOBILE_BREAKPOINT = 768;

const TABLET_UA_RE = /iPad|Tablet|Android(?!.*Mobile)|Silk|Kindle|PlayBook/i;
const REPORTED_NON_FATAL_ERRORS = new Set<string>();

function reportNonFatalMobileError(key: string, error: unknown): void {
  if (REPORTED_NON_FATAL_ERRORS.has(key)) {
    return;
  }
  REPORTED_NON_FATAL_ERRORS.add(key);
  handleError(error, { context: `useMobile.${key}`, showToast: false });
}

const hasCoarsePointer = (): boolean => {
  try {
    return !!(window.matchMedia && window.matchMedia('(pointer: coarse)').matches);
  } catch (error) {
    reportNonFatalMobileError('hasCoarsePointer', error);
    return false;
  }
};

